  ('aboriginal-f0899a01-moex-00378', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於刑法「偽造文書」罪，下列敘述何者正確？', '["以實際上根本不存在之人的名義製作文書，並不構成犯罪", "甲未經乙的授權而以乙的名義製作私文書，構成偽造私文書罪", "偽造文書罪所謂「足以生損害於公眾或他人」，係以發生實際上損害為必要", "凡公務員所製作的文書，都是公文書，擅自偽造就會構成偽造公文書罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
