  ('aboriginal-f0899a01-moex-00383', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲竊盜乙之皮夾，乙當場發現後，追打甲欲要回皮夾，甲為逃脫將乙打昏，甲構成下列何罪？', '["刑法第320條第2項竊占罪", "刑法第328條第2項強盜得利罪", "刑法第329條準強盜罪", "刑法第347條第1項擄人勒贖罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00384', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '關於殺人罪的敘述，下列何者錯誤？', '["胎兒不是刑法殺人罪保護的客體", "自殺不構成殺人罪", "教唆或幫助他人自殺，為我國刑法所不處罰之行為", "屍體非殺人罪之行為客體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00385', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '下列情形中，何者不成立刑法第294條違背義務遺棄罪？', '["甲駕駛汽車肇事致乙昏迷後，不理會乙而自行離開現場", "保姆甲將受託照護之3歲幼兒乙單獨遺留在家中1日，自行出遊", "銀行保全甲對於銀行門口外昏迷之老人乙置之不理", "登山嚮導甲於途中，將受傷昏迷之隊員乙遺留原處，未為任何處置即離開現場"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00386', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲先透過網站的後門，侵入某政府機關網頁，再於其網頁上，植入從他人處購得之惡意電腦程式，只要一 般網友點選該政府機關網頁，就會下載該程式而使其電腦中毒。甲之行為不成立下列何罪？', '["刑法第358條入侵電腦罪", "刑法第359條變更他人電磁紀錄罪", "刑法第360條干擾他人電腦設備罪", "刑法第362條製作惡意程式罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9d980fdd98d0", "answer_pdf_sha1": "f8fdd9604e08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
